import org.owasp.encoder.Encode;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulated user input received from a form submission
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly escape user input before including it in the output
        String escapedUserInput = Encode.forHtml(userInput);

        String output = "<div>" + escapedUserInput + "</div>";

        // Output the sanitized data to the page
        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println(output);
            out.close();
            System.out.println("Sanitized output written to output.html");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
